import{_ as a,o as l,c as i,a4 as t}from"./chunks/framework.CgwWDRUJ.js";const u=JSON.parse('{"title":"3.3 Non-Functional Requirements","description":"","frontmatter":{},"headers":[],"relativePath":"rad/proposed-system/non-functional.md","filePath":"rad/proposed-system/non-functional.md"}'),r={name:"rad/proposed-system/non-functional.md"};function s(n,e,o,h,g,c){return l(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="_3-3-non-functional-requirements" tabindex="-1">3.3 Non-Functional Requirements <a class="header-anchor" href="#_3-3-non-functional-requirements" aria-label="Permalink to “3.3 Non-Functional Requirements”">​</a></h1><h2 id="_3-3-1-usability" tabindex="-1">3.3.1 Usability <a class="header-anchor" href="#_3-3-1-usability" aria-label="Permalink to “3.3.1 Usability”">​</a></h2><h3 id="user-interface-design" tabindex="-1">User Interface Design <a class="header-anchor" href="#user-interface-design" aria-label="Permalink to “User Interface Design”">​</a></h3><ul><li><strong>NFR-U.1.1</strong>: The mobile app shall follow Material Design 3 guidelines for Android and Human Interface Guidelines for iOS</li><li><strong>NFR-U.1.2</strong>: The web interface shall be responsive and functional on devices from 320px to 2560px width</li><li><strong>NFR-U.1.3</strong>: All interactive elements shall have minimum 48x48 dp touch target size</li><li><strong>NFR-U.1.4</strong>: The system shall support dark and light themes</li></ul><h3 id="user-experience" tabindex="-1">User Experience <a class="header-anchor" href="#user-experience" aria-label="Permalink to “User Experience”">​</a></h3><ul><li><strong>NFR-U.2.1</strong>: New users shall complete onboarding in &lt; 5 minutes</li><li><strong>NFR-U.2.2</strong>: Core user flows shall require ≤ 3 taps/clicks to complete</li><li><strong>NFR-U.2.3</strong>: All error messages shall be clear and provide actionable solutions</li><li><strong>NFR-U.2.4</strong>: The system shall provide contextual help and tooltips for complex features</li><li><strong>NFR-U.2.5</strong>: Load times for profile pages shall be ≤ 1 second (P95)</li></ul><h3 id="accessibility" tabindex="-1">Accessibility <a class="header-anchor" href="#accessibility" aria-label="Permalink to “Accessibility”">​</a></h3><ul><li><strong>NFR-U.3.1</strong>: The application shall comply with WCAG 2.1 Level AA standards</li><li><strong>NFR-U.3.2</strong>: All text shall have minimum contrast ratio of 4.5:1 (normal text) or 3:1 (large text)</li><li><strong>NFR-U.3.3</strong>: The mobile app shall support screen readers (VoiceOver, TalkBack)</li><li><strong>NFR-U.3.4</strong>: All interactive elements shall be keyboard navigable</li><li><strong>NFR-U.3.5</strong>: The system shall support text size customization</li></ul><h2 id="_3-3-2-reliability" tabindex="-1">3.3.2 Reliability <a class="header-anchor" href="#_3-3-2-reliability" aria-label="Permalink to “3.3.2 Reliability”">​</a></h2><h3 id="availability" tabindex="-1">Availability <a class="header-anchor" href="#availability" aria-label="Permalink to “Availability”">​</a></h3><ul><li><strong>NFR-R.1.1</strong>: System shall maintain 99.5% uptime (&lt; 3.6 hours downtime/month)</li><li><strong>NFR-R.1.2</strong>: All critical features shall have automatic failover mechanisms</li><li><strong>NFR-R.1.3</strong>: Database shall be replicated across at least 2 geographic regions</li><li><strong>NFR-R.1.4</strong>: API servers shall be load-balanced with auto-scaling</li></ul><h3 id="error-handling" tabindex="-1">Error Handling <a class="header-anchor" href="#error-handling" aria-label="Permalink to “Error Handling”">​</a></h3><ul><li><strong>NFR-R.2.1</strong>: The system shall gracefully handle network interruptions</li><li><strong>NFR-R.2.2</strong>: Failed requests shall be automatically retried up to 3 times with exponential backoff</li><li><strong>NFR-R.2.3</strong>: All errors shall be logged with full context for debugging</li><li><strong>NFR-R.2.4</strong>: User sessions shall be recovered automatically upon reconnection</li></ul><h3 id="data-integrity" tabindex="-1">Data Integrity <a class="header-anchor" href="#data-integrity" aria-label="Permalink to “Data Integrity”">​</a></h3><ul><li><strong>NFR-R.3.1</strong>: All data modifications shall be atomically committed</li><li><strong>NFR-R.3.2</strong>: Database shall support ACID transactions</li><li><strong>NFR-R.3.3</strong>: Backup shall occur every 6 hours with point-in-time recovery capability</li><li><strong>NFR-R.3.4</strong>: Data consistency shall be validated through checksums</li></ul><h3 id="crash-recovery" tabindex="-1">Crash Recovery <a class="header-anchor" href="#crash-recovery" aria-label="Permalink to “Crash Recovery”">​</a></h3><ul><li><strong>NFR-R.4.1</strong>: Mobile app shall not crash under normal operating conditions</li><li><strong>NFR-R.4.2</strong>: Unsaved user input shall be automatically recovered after crashes</li><li><strong>NFR-R.4.3</strong>: Crash logs shall be automatically reported for analysis</li></ul><h2 id="_3-3-3-performance" tabindex="-1">3.3.3 Performance <a class="header-anchor" href="#_3-3-3-performance" aria-label="Permalink to “3.3.3 Performance”">​</a></h2><h3 id="response-times" tabindex="-1">Response Times <a class="header-anchor" href="#response-times" aria-label="Permalink to “Response Times”">​</a></h3><ul><li><strong>NFR-P.1.1</strong>: API response time (P95) shall be ≤ 500ms for read operations</li><li><strong>NFR-P.1.2</strong>: Search queries shall respond within 2 seconds for standard filters</li><li><strong>NFR-P.1.3</strong>: Profile page shall load and render within 1 second (P95)</li><li><strong>NFR-P.1.4</strong>: Chat messages shall sync within 500ms (P95)</li><li><strong>NFR-P.1.5</strong>: Matching algorithm shall complete within 5 seconds for 10K+ profiles</li></ul><h3 id="throughput" tabindex="-1">Throughput <a class="header-anchor" href="#throughput" aria-label="Permalink to “Throughput”">​</a></h3><ul><li><strong>NFR-P.2.1</strong>: System shall support at least 10,000 concurrent users</li><li><strong>NFR-P.2.2</strong>: API shall handle 1,000 requests per second</li><li><strong>NFR-P.2.3</strong>: Database shall support 500 concurrent connections</li><li><strong>NFR-P.2.4</strong>: Chat system shall handle 100 messages per second</li></ul><h3 id="resource-utilization" tabindex="-1">Resource Utilization <a class="header-anchor" href="#resource-utilization" aria-label="Permalink to “Resource Utilization”">​</a></h3><ul><li><strong>NFR-P.3.1</strong>: Mobile app APK/IPA size shall not exceed 150MB</li><li><strong>NFR-P.3.2</strong>: Memory usage on mobile devices shall not exceed 200MB during normal operation</li><li><strong>NFR-P.3.3</strong>: API server CPU usage shall not exceed 70% under peak load</li><li><strong>NFR-P.3.4</strong>: Database query time shall be optimized with indexes (&lt; 100ms for typical queries)</li></ul><h3 id="optimization" tabindex="-1">Optimization <a class="header-anchor" href="#optimization" aria-label="Permalink to “Optimization”">​</a></h3><ul><li><strong>NFR-P.4.1</strong>: Images shall be optimized and compressed (WebP format supported)</li><li><strong>NFR-P.4.2</strong>: API responses shall support field filtering to reduce payload size</li><li><strong>NFR-P.4.3</strong>: Database queries shall be optimized and avoid N+1 problems</li><li><strong>NFR-P.4.4</strong>: Frontend shall implement lazy loading and virtualization for lists</li></ul><h2 id="_3-3-4-supportability" tabindex="-1">3.3.4 Supportability <a class="header-anchor" href="#_3-3-4-supportability" aria-label="Permalink to “3.3.4 Supportability”">​</a></h2><h3 id="maintainability" tabindex="-1">Maintainability <a class="header-anchor" href="#maintainability" aria-label="Permalink to “Maintainability”">​</a></h3><ul><li><strong>NFR-S.1.1</strong>: Code shall follow established style guides and conventions</li><li><strong>NFR-S.1.2</strong>: All public APIs shall be documented with Swagger/OpenAPI</li><li><strong>NFR-S.1.3</strong>: Database schema changes shall be managed through migrations</li><li><strong>NFR-S.1.4</strong>: Code shall achieve minimum 70% test coverage</li><li><strong>NFR-S.1.5</strong>: All functions shall have documentation comments</li></ul><h3 id="extensibility" tabindex="-1">Extensibility <a class="header-anchor" href="#extensibility" aria-label="Permalink to “Extensibility”">​</a></h3><ul><li><strong>NFR-S.2.1</strong>: Architecture shall support adding new modules without major refactoring</li><li><strong>NFR-S.2.2</strong>: Plugin system shall allow third-party integrations</li><li><strong>NFR-S.2.3</strong>: API versioning shall support backward compatibility</li><li><strong>NFR-S.2.4</strong>: Database schema shall support future feature additions</li></ul><h3 id="debugging" tabindex="-1">Debugging <a class="header-anchor" href="#debugging" aria-label="Permalink to “Debugging”">​</a></h3><ul><li><strong>NFR-S.3.1</strong>: System shall provide comprehensive logging at DEBUG, INFO, WARN, ERROR levels</li><li><strong>NFR-S.3.2</strong>: Logs shall include request/response tracing IDs</li><li><strong>NFR-S.3.3</strong>: Error tracking system shall aggregate and analyze exceptions</li><li><strong>NFR-S.3.4</strong>: Developer tools shall support local testing and staging environments</li></ul><h2 id="_3-3-5-implementation" tabindex="-1">3.3.5 Implementation <a class="header-anchor" href="#_3-3-5-implementation" aria-label="Permalink to “3.3.5 Implementation”">​</a></h2><h3 id="technology-stack" tabindex="-1">Technology Stack <a class="header-anchor" href="#technology-stack" aria-label="Permalink to “Technology Stack”">​</a></h3><ul><li><strong>NFR-I.1.1</strong>: Mobile: Flutter (Dart language)</li><li><strong>NFR-I.1.2</strong>: Backend: Python with Django and Django REST Framework</li><li><strong>NFR-I.1.3</strong>: Database: PostgreSQL (v12+)</li><li><strong>NFR-I.1.4</strong>: Caching: Redis for session/cache management</li><li><strong>NFR-I.1.5</strong>: Deployment: Docker containerization</li><li><strong>NFR-I.1.6</strong>: CI/CD: GitHub Actions or GitLab CI</li></ul><p><strong>Repository note:</strong> The current GitHub repository (Simo-2004/TravelMate) is a Flutter mobile application (MVP) and <strong>does not</strong> include a backend implementation. The backend technology stack listed above is a planned/ preferred stack for Phase 2+ and should be treated as a recommendation rather than a current implementation.</p><p>Currently implemented in repository:</p><ul><li>Mobile: Flutter (Dart) — implemented (<code>lib/</code> contains the full Flutter app)</li><li>Local persistence: SharedPreferences-based repositories (<code>lib/shared/data/*.dart</code>) — implemented</li><li>State management: ValueNotifier-based singleton stores (<code>lib/shared/state/*.dart</code>) — implemented</li></ul><p>Planned (not present in repository):</p><ul><li>Django REST Framework backend, PostgreSQL database, Redis cache, server-side search, and messaging infrastructure.</li></ul><h3 id="development-standards" tabindex="-1">Development Standards <a class="header-anchor" href="#development-standards" aria-label="Permalink to “Development Standards”">​</a></h3><ul><li><strong>NFR-I.2.1</strong>: All code shall follow PEP-8 (Python) and Dart style guides</li><li><strong>NFR-I.2.2</strong>: Code reviews shall be mandatory before merge</li><li><strong>NFR-I.2.3</strong>: Automated testing shall run on all pull requests</li><li><strong>NFR-I.2.4</strong>: Security scanning shall be integrated into CI/CD pipeline</li></ul><h3 id="version-control" tabindex="-1">Version Control <a class="header-anchor" href="#version-control" aria-label="Permalink to “Version Control”">​</a></h3><ul><li><strong>NFR-I.3.1</strong>: Git-based version control with semantic versioning</li><li><strong>NFR-I.3.2</strong>: Main branch shall always contain production-ready code</li><li><strong>NFR-I.3.3</strong>: Feature branches shall be used for development</li><li><strong>NFR-I.3.4</strong>: Release tags shall document version history</li></ul><h2 id="_3-3-6-interface" tabindex="-1">3.3.6 Interface <a class="header-anchor" href="#_3-3-6-interface" aria-label="Permalink to “3.3.6 Interface”">​</a></h2><h3 id="api-standards" tabindex="-1">API Standards <a class="header-anchor" href="#api-standards" aria-label="Permalink to “API Standards”">​</a></h3><ul><li><strong>NFR-IF.1.1</strong>: All APIs shall follow RESTful principles</li><li><strong>NFR-IF.1.2</strong>: API responses shall use JSON format</li><li><strong>NFR-IF.1.3</strong>: API shall use standard HTTP status codes (200, 201, 400, 401, 403, 404, 500)</li><li><strong>NFR-IF.1.4</strong>: API rate limiting: 1000 requests/hour per user</li><li><strong>NFR-IF.1.5</strong>: API endpoints shall include pagination, filtering, and sorting</li></ul><h3 id="authentication-authorization" tabindex="-1">Authentication &amp; Authorization <a class="header-anchor" href="#authentication-authorization" aria-label="Permalink to “Authentication &amp; Authorization”">​</a></h3><ul><li><strong>NFR-IF.2.1</strong>: APIs shall use JWT Bearer tokens for authentication</li><li><strong>NFR-IF.2.2</strong>: Tokens shall expire after 24 hours</li><li><strong>NFR-IF.2.3</strong>: Role-based access control (RBAC) shall enforce permissions</li><li><strong>NFR-IF.2.4</strong>: All sensitive endpoints shall require authentication</li><li><strong>NFR-IF.2.5</strong>: API shall support OAuth2 for third-party integrations</li></ul><h3 id="data-format" tabindex="-1">Data Format <a class="header-anchor" href="#data-format" aria-label="Permalink to “Data Format”">​</a></h3><ul><li><strong>NFR-IF.3.1</strong>: Timestamps shall use ISO 8601 format (UTC)</li><li><strong>NFR-IF.3.2</strong>: Currencies shall be represented with ISO 4217 codes</li><li><strong>NFR-IF.3.3</strong>: Coordinates shall use WGS 84 (GPS) format</li><li><strong>NFR-IF.3.4</strong>: Phone numbers shall support international format (E.164)</li></ul><h2 id="_3-3-7-packaging" tabindex="-1">3.3.7 Packaging <a class="header-anchor" href="#_3-3-7-packaging" aria-label="Permalink to “3.3.7 Packaging”">​</a></h2><h3 id="mobile-distribution" tabindex="-1">Mobile Distribution <a class="header-anchor" href="#mobile-distribution" aria-label="Permalink to “Mobile Distribution”">​</a></h3><ul><li><strong>NFR-PK.1.1</strong>: iOS app shall be distributed via Apple App Store</li><li><strong>NFR-PK.1.2</strong>: Android app shall be distributed via Google Play Store</li><li><strong>NFR-PK.1.3</strong>: Apps shall support minimum OS versions: iOS 12+, Android 7+</li><li><strong>NFR-PK.1.4</strong>: App shall be code-signed with valid certificates</li></ul><h3 id="web-deployment" tabindex="-1">Web Deployment <a class="header-anchor" href="#web-deployment" aria-label="Permalink to “Web Deployment”">​</a></h3><ul><li><strong>NFR-PK.2.1</strong>: Web app shall be deployable to cloud platforms (AWS, GCP, Azure)</li><li><strong>NFR-PK.2.2</strong>: Docker images shall be published to container registries</li><li><strong>NFR-PK.2.3</strong>: Infrastructure as Code (Terraform/CloudFormation) shall define deployments</li><li><strong>NFR-PK.2.4</strong>: Environment-specific configurations shall be managed externally</li></ul><h3 id="release-management" tabindex="-1">Release Management <a class="header-anchor" href="#release-management" aria-label="Permalink to “Release Management”">​</a></h3><ul><li><strong>NFR-PK.3.1</strong>: Releases shall follow semantic versioning (MAJOR.MINOR.PATCH)</li><li><strong>NFR-PK.3.2</strong>: Release notes shall document features, fixes, and known issues</li><li><strong>NFR-PK.3.3</strong>: Beta releases shall be tested by internal teams before public release</li><li><strong>NFR-PK.3.4</strong>: Backward compatibility shall be maintained for at least 2 previous versions</li></ul><h2 id="_3-3-8-legal" tabindex="-1">3.3.8 Legal <a class="header-anchor" href="#_3-3-8-legal" aria-label="Permalink to “3.3.8 Legal”">​</a></h2><h3 id="privacy-data-protection" tabindex="-1">Privacy &amp; Data Protection <a class="header-anchor" href="#privacy-data-protection" aria-label="Permalink to “Privacy &amp; Data Protection”">​</a></h3><ul><li><strong>NFR-L.1.1</strong>: System shall comply with GDPR regulations</li><li><strong>NFR-L.1.2</strong>: Users shall have right to data export in machine-readable format (JSON/CSV)</li><li><strong>NFR-L.1.3</strong>: Users shall have right to be forgotten (account deletion with data removal)</li><li><strong>NFR-L.1.4</strong>: Privacy policy shall be presented and accepted during registration</li><li><strong>NFR-L.1.5</strong>: Data retention policies shall comply with regulations (delete after account closure)</li></ul><h3 id="security-compliance" tabindex="-1">Security &amp; Compliance <a class="header-anchor" href="#security-compliance" aria-label="Permalink to “Security &amp; Compliance”">​</a></h3><ul><li><strong>NFR-L.2.1</strong>: All passwords shall be hashed using bcrypt (or better)</li><li><strong>NFR-L.2.2</strong>: Sensitive data shall be encrypted at rest (AES-256)</li><li><strong>NFR-L.2.3</strong>: Communications shall use TLS 1.3+</li><li><strong>NFR-L.2.4</strong>: System shall conduct annual security audits</li><li><strong>NFR-L.2.5</strong>: Security incidents shall be logged and tracked</li></ul><h3 id="terms-of-service" tabindex="-1">Terms of Service <a class="header-anchor" href="#terms-of-service" aria-label="Permalink to “Terms of Service”">​</a></h3><ul><li><strong>NFR-L.3.1</strong>: Terms of Service shall be agreed upon at registration</li><li><strong>NFR-L.3.2</strong>: Changes to ToS shall require user acknowledgment</li><li><strong>NFR-L.3.3</strong>: System shall maintain audit trail of user consent</li><li><strong>NFR-L.3.4</strong>: Prohibited content policies shall be clearly defined</li></ul><h3 id="intellectual-property" tabindex="-1">Intellectual Property <a class="header-anchor" href="#intellectual-property" aria-label="Permalink to “Intellectual Property”">​</a></h3><ul><li><strong>NFR-L.4.1</strong>: User-generated content license terms shall be clearly stated</li><li><strong>NFR-L.4.2</strong>: Copyright notices shall be included in all materials</li><li><strong>NFR-L.4.3</strong>: Third-party library licenses shall be compatible with project license</li></ul><h3 id="liability" tabindex="-1">Liability <a class="header-anchor" href="#liability" aria-label="Permalink to “Liability”">​</a></h3><ul><li><strong>NFR-L.5.1</strong>: Terms shall limit liability for user interactions</li><li><strong>NFR-L.5.2</strong>: Terms shall address dispute resolution mechanisms</li><li><strong>NFR-L.5.3</strong>: Terms shall include liability limitations for service interruptions</li></ul>',70)])])}const m=a(r,[["render",s]]);export{u as __pageData,m as default};
